import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../core/utils/app_utils.dart';import '../auth/auth_provider.dart';class SettingsScreen extends ConsumerWidget{const SettingsScreen({super.key});Future<void> change(BuildContext context,WidgetRef ref)async{final f=GlobalKey<FormState>(),old=TextEditingController(),next=TextEditingController();final ok=await showDialog<bool>(context:context,builder:(x)=>AlertDialog(title:const Text('Change PIN'),content:Form(key:f,child:Column(mainAxisSize:MainAxisSize.min,children:[TextFormField(controller:old,maxLength:4,obscureText:true,keyboardType:TextInputType.number,decoration:const InputDecoration(labelText:'Current PIN',counterText:''),validator:Validators.pin),const SizedBox(height:10),TextFormField(controller:next,maxLength:4,obscureText:true,keyboardType:TextInputType.number,decoration:const InputDecoration(labelText:'New PIN',counterText:''),validator:Validators.pin)])),actions:[TextButton(onPressed:()=>Navigator.pop(x),child:const Text('Cancel')),FilledButton(onPressed:(){if(f.currentState!.validate())Navigator.pop(x,true);},child:const Text('Change'))]));if(ok==true){final done=await ref.read(authProvider.notifier).changePin(old.text,next.text);if(context.mounted)ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text(done?'PIN changed':'Current PIN is incorrect')));}}@override Widget build(BuildContext context,WidgetRef ref){final p=ref.watch(authProvider).profile;return Scaffold(appBar:AppBar(title:const Text('Settings')),body:ListView(padding:const EdgeInsets.all(16),children:[Card(child:ListTile(leading:const CircleAvatar(child:Icon(Icons.storefront)),title:Text(p?.business??'',style:const TextStyle(fontWeight:FontWeight.w900)),subtitle:Text('${p?.owner??''} · ${p?.location??''}'))),const SizedBox(height:14),Card(child:Column(children:[ListTile(leading:const Icon(Icons.pin),title:const Text('Change PIN'),onTap:()=>change(context,ref)),const Divider(height:1),const ListTile(leading:Icon(Icons.cloud_off),title:Text('Cloud sync'),subtitle:Text('Offline now; Supabase-ready next phase')),const Divider(height:1),ListTile(leading:const Icon(Icons.logout),title:const Text('Lock app'),onTap:()=>ref.read(authProvider.notifier).logout())])),const SizedBox(height:14),Card(child:ListTile(leading:Icon(Icons.delete_forever,color:Theme.of(context).colorScheme.error),title:Text('Reset business setup',style:TextStyle(color:Theme.of(context).colorScheme.error)),onTap:()=>ref.read(authProvider.notifier).reset()))]));}}
